#include <bits/stdc++.h>
using namespace std;

const int N=1.2e5+10,M=5e6;

int T,n,m,tot,s[N],t[N],ps[N],pt[N],f[N][17],fs[N][17],ft[N][17],dep[N],d[M],q[M],hh,tt;
vector<int> e[N],g[M];

int New(){
    g[++tot].clear();
    d[tot]=0;
    return tot;
}

void add(int x,int y){
    g[x].push_back(y);
    d[y]++;
	//printf("%d %d\n",x,y);
}

void dfs(int x,int fa){
    dep[x]=dep[fa]+1;
    f[x][0]=fa;
    fs[x][0]=New();
    ft[x][0]=New();
    if(ps[x]) add(ps[x],fs[x][0]);
    if(pt[x]) add(ft[x][0],pt[x]);
    for(int i=1;(1<<i)<=dep[x];i++){
        f[x][i]=f[f[x][i-1]][i-1];
        fs[x][i]=New(),ft[x][i]=New();
        add(fs[x][i-1],fs[x][i]);
        add(fs[f[x][i-1]][i-1],fs[x][i]);
        add(ft[x][i],ft[x][i-1]);
        add(ft[x][i],ft[f[x][i-1]][i-1]);
    }
    for(int y:e[x])
        if(y!=fa)
            dfs(y,x);
}

int LCA(int x,int y){
    if(dep[x]<dep[y])
        swap(x,y);
    for(int i=16;i>=0;i--)
        if(dep[f[x][i]]>=dep[y])
            x=f[x][i];
    if(x==y)
        return x;
    for(int i=16;i>=0;i--)
        if(f[x][i]!=f[y][i])
            x=f[x][i],y=f[y][i];
    return f[x][0];
}

int main(){
    scanf("%d",&T);
    while(T--){
        scanf("%d",&n);
        for(int i=1;i<=n;i++){
            e[i].clear();
            ps[i]=pt[i]=0;
            for(int j=0;j<17;j++)
                f[i][j]=0;
        }
        for(int i=1,u,v;i<n;i++){
            scanf("%d%d",&u,&v);
            e[u].push_back(v);
            e[v].push_back(u);
        }
        scanf("%d",&m);
        for(int i=1;i<=m;i++){
            scanf("%d%d",&s[i],&t[i]);
            ps[s[i]]=i,pt[t[i]]=i;
        }
        tot=0;
        for(int i=1;i<=m;i++) tot=New();
        dfs(1,0);
        //puts("OK");;;;;;;;;;;;;;;;;;;;
        for(int i=1;i<=m;i++){
            int x=s[i],y=t[i],lca=LCA(x,y);
            x=f[x][0];
            for(int j=16;j>=0 && x;j--)
                if(dep[f[x][j]]>=dep[lca]-1 && (1<<j)<=dep[x]){
                    add(fs[x][j],i);
                    x=f[x][j];
                }
            for(int j=16;j>=0 && y;j--)
                if(dep[f[y][j]]>=dep[lca] && (1<<j)<=dep[y]){
                    add(fs[y][j],i);
                    y=f[y][j];
                }
            x=s[i],y=f[t[i]][0];
            for(int j=16;j>=0 && x;j--)
                if(dep[f[x][j]]>=dep[lca] && (1<<j)<=dep[x]){
                    add(i,ft[x][j]);
                    x=f[x][j];
                }
            for(int j=16;j>=0 && y;j--)
                if(dep[f[y][j]]>=dep[lca]-1 && (1<<j)<=dep[y]){
                    add(i,ft[y][j]);
                    y=f[y][j];
                }
        }
        hh=1,tt=0;
        for(int i=1;i<=tot;i++)
            if(!d[i])
                q[++tt]=i;
        int cnt=0;
        while(hh<=tt){
            int x=q[hh++];
            cnt+=(x<=m);
            for(int y:g[x])
                if(!(--d[y]))
                    q[++tt]=y;
        }
        if(cnt<m)
            puts("No");
        else
            puts("Yes");
    }
    return 0;
}
